from mcp.server.fastmcp import FastMCP

# Шаг 1: создаём сервер с именем
mcp = FastMCP("team-glossary")

# Шаг 2: регистрируем инструмент — обычную функцию
@mcp.tool()
def define_term(term: str) -> str:
    """Возвращает определение термина из глоссария команды.
    Используй, когда пользователь спрашивает значение внутреннего термина."""
    glossary = {
        "МДЛП": "Мониторинг движения лекарственных препаратов",
        "ПФО": "Приволжский федеральный округ",
    }
    return glossary.get(term, f"Термина «{term}» нет в глоссарии")

# Шаг 3: запускаем транспорт stdio
mcp.run()

